import os, base64, gzip
base = os.path.dirname(os.path.abspath(__file__))
FILES = [
  ('src\\\\lib\\\\seoConfig.ts', ''),
  ('src\\\\app\\\\sitemap.xml\\\\route.ts', ''),
  ('src\\\\app\\\\robots.txt\\\\route.ts', ''),
  ('src\\\\app\\\\layout.tsx', ''),
]
ok = 0
for rel, data in FILES:
    try:
        dest = os.path.join(base, rel)
        os.makedirs(os.path.dirname(dest), exist_ok=True)
        with open(dest, "w", encoding="utf-8", newline="\n") as f:
            f.write(gzip.decompress(base64.b64decode(data)).decode("utf-8"))
        print("OK:", rel)
        ok += 1
    except Exception as e:
        print("ERRO:", rel, e)

FIX_PAGES = ''
exec(gzip.decompress(base64.b64decode(FIX_PAGES)).decode("utf-8"))

print()
print(f"Total: {ok}/4 arquivos SEO instalados")
print("SEO profissional - metadata, sitemap, robots, schema.org!")
print("Rode: npm run build")